mapper.select:
select count(1)
from flight_route_dish frd
         inner join flight_info fi on fi.departure = frd.departure and fi.destination = frd.destination
where fi.flight_number = #{flightNumber}
  and frd.dish_id = #{dishId}
  and (case
           when ifnull(frd.cabin_type, 3) = 0 then 3
           else ifnull(frd.cabin_type, 3)
       end) = #{cabinType}

      and frd.id != #{excludeId}
